	if evidenceVariantnistsu == "" {
		return false, 0, "variant"
	}
	if requests < 3 {
		return false, requests, "request-coverage"
	}
	if closedBodies != requests {
		return false, closedBodies, "body-cleanup"
	}
	if boundedBodies != requests {
		return false, boundedBodies, "body-budget"
	}
